const allInputs = $input.all();

// CONFIGURAÇÕES
const MAX_HORARIOS = 10; // Fácil de ajustar: quantidade máxima de horários a retornar
const diasPadrao = 15; // Dias para buscar caso nenhuma data definida
const diasDataAlternativa = 7; // Dias para buscar se data_alternativa existir
const diasDataConsulta = 10; // Dias para buscar se data_consulta_reuniao existir

const agendaSemana = {
  1: ['09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00'], // Segunda
  2: ['09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00'], // Terça
  3: ['09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00'], // Quarta
  4: ['09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00'], // Quinta
  5: ['09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00'], // Sexta
  6: [], // Sábado
  0: [] // Domingo
};

// Extrair eventos com start e end válidos
const eventos = allInputs
  .filter(item => item.json?.start?.dateTime && item.json?.end?.dateTime)
  .map(item => ({
    inicio: new Date(item.json.start.dateTime),
    fim: new Date(item.json.end.dateTime)
  }));

// Puxar dados do cliente de qualquer item (todos têm o mesmo valor)
const cliente = allInputs[0]?.json || {};

// Debug: verificar dados do cliente
console.log('Dados do cliente:', {
  nome: cliente.nome_cliente,
  email: cliente.email_cliente,
  telefone: cliente.telefone_cliente,
  data_consulta: cliente.data_consulta_reuniao,
  data_alternativa: cliente.data_alternativa
});

console.log('Eventos encontrados:', eventos.length);

// --- DATA DE REFERÊNCIA ---
let inicioBusca;
let diasParaBuscar = diasPadrao;
let horarioEspecificoSolicitado = null;
const agora = new Date();

if (cliente.data_alternativa) {
  inicioBusca = new Date(cliente.data_alternativa);
  diasParaBuscar = diasDataAlternativa;
  console.log('Usando data_alternativa:', cliente.data_alternativa);
} else if (cliente.data_consulta_reuniao) {
  const dataConsulta = new Date(cliente.data_consulta_reuniao);
  inicioBusca = dataConsulta;
  diasParaBuscar = diasDataConsulta;

  // Extrair horário específico solicitado
  horarioEspecificoSolicitado = {
    data: dataConsulta.toISOString().slice(0, 10),
    hora: dataConsulta.toLocaleTimeString('pt-BR', { 
      hour: '2-digit', 
      minute: '2-digit',
      timeZone: 'America/Sao_Paulo'
    })
  };

  console.log('Usando data_consulta_reuniao:', cliente.data_consulta_reuniao);
  console.log('Horário específico solicitado:', horarioEspecificoSolicitado);
} else {
  inicioBusca = agora;
  console.log('Usando data atual');
}

// Helper para criar horário completo
function criarHorarioCompleto(dataISO, horaMin) {
  return `${dataISO}T${horaMin}:00-03:00`;
}

// Helper para somar 1 hora ao horário
function somarUmaHora(horaStr) {
  const [hora, minuto] = horaStr.split(':');
  const novaHora = (parseInt(hora) + 1).toString().padStart(2, '0');
  return `${novaHora}:${minuto}`;
}

// Helper para formatar data
function formatarData(dt) {
  return dt.toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit' });
}

const horariosLivres = [];

// PRIMEIRA PRIORIDADE: Verificar se o horário específico solicitado está disponível
if (horarioEspecificoSolicitado) {
  console.log('\n🎯 VERIFICANDO HORÁRIO ESPECÍFICO SOLICITADO');

  const dataISO = horarioEspecificoSolicitado.data;
  const horaStr = horarioEspecificoSolicitado.hora;
  const dataSolicitada = new Date(dataISO + 'T00:00:00');
  const diaSemana = dataSolicitada.getDay();
  const horariosPermitidos = agendaSemana[diaSemana] || [];

  console.log(`Data: ${dataISO} (${formatarData(dataSolicitada)})`);
  console.log(`Horário solicitado: ${horaStr}`);
  console.log(`Horários permitidos no dia: ${horariosPermitidos.join(', ')}`);

  // Verificar se o horário solicitado está nos horários permitidos
  if (horariosPermitidos.includes(horaStr)) {
    const inicioStr = criarHorarioCompleto(dataISO, horaStr);
    const inicioSlot = new Date(inicioStr);
    const fimSlot = new Date(inicioSlot.getTime() + 60 * 60 * 1000);

    // Verificar se há conflito com eventos existentes
    const ocupados = eventos.filter(ev =>
      ev.inicio.toISOString().startsWith(dataISO)
    );

    const conflitante = ocupados.some(ev =>
      (inicioSlot < ev.fim) && (fimSlot > ev.inicio)
    );

    const noFuturo = inicioSlot > agora;

    console.log(`Status: ${conflitante ? '❌ OCUPADO' : '✅ LIVRE'} | ${noFuturo ? '✅ FUTURO' : '❌ PASSADO'}`);

    if (!conflitante && noFuturo) {
      const horaFim = somarUmaHora(horaStr);
      const fimStr = criarHorarioCompleto(dataISO, horaFim);

      horariosLivres.push({
        cliente_nome: cliente.nome_cliente || '',
        cliente_email: cliente.email_cliente || '',
        cliente_telefone: cliente.telefone_cliente || '',
        data: dataISO,
        dia_semana: formatarData(inicioSlot),
        horario: horaStr,
        horario_fim: horaFim,
        inicio: inicioStr,
        fim: fimStr,
        inicio_utc: inicioSlot.toISOString(),
        fim_utc: fimSlot.toISOString(),
        tipo: 'HORARIO_SOLICITADO'
      });

      console.log(`🎉 HORÁRIO ESPECÍFICO DISPONÍVEL! Retornando: ${horaStr} - ${horaFim}`);
    } else {
      console.log(`❌ Horário específico não disponível. Motivo: ${conflitante ? 'ocupado' : 'no passado'}`);
    }
  } else {
    console.log(`❌ Horário ${horaStr} não está nos horários de funcionamento deste dia`);
  }
}

// Se já encontrou o horário específico, retornar apenas ele
if (horariosLivres.length > 0) {
  console.log('\n✅ Horário específico encontrado! Retornando apenas ele.');
  return horariosLivres.map(h => ({ json: h }));
}

// SEGUNDA PRIORIDADE: Buscar outros horários disponíveis
console.log('\n🔍 BUSCANDO HORÁRIOS ALTERNATIVOS');

// Procurar horários disponíveis
for (let d = 0; d < diasParaBuscar && horariosLivres.length < MAX_HORARIOS; d++) {
  const dataBusca = new Date(inicioBusca);
  dataBusca.setDate(dataBusca.getDate() + d);
  const dataISO = dataBusca.toISOString().slice(0, 10);
  const diaSemana = dataBusca.getDay();
  const horariosHoje = agendaSemana[diaSemana] || [];

  if (horariosHoje.length === 0) continue;

  // Eventos ocupados neste dia
  const ocupados = eventos.filter(ev =>
    ev.inicio.toISOString().startsWith(dataISO)
  );

  console.log(`\nDia ${dataISO} (${formatarData(dataBusca)}):`);
  console.log('Horários disponíveis:', horariosHoje);
  console.log('Eventos ocupados:', ocupados.length);

  for (const horaStr of horariosHoje) {
    const inicioStr = criarHorarioCompleto(dataISO, horaStr);
    const inicioSlot = new Date(inicioStr);
    const fimSlot = new Date(inicioSlot.getTime() + 60 * 60 * 1000); // +1 hora

    // Verificar conflitos
    const conflitante = ocupados.some(ev =>
      (inicioSlot < ev.fim) && (fimSlot > ev.inicio)
    );

    // Verificar se é no futuro
    const noFuturo = inicioSlot > agora;

    console.log(`  ${horaStr}: ${conflitante ? 'OCUPADO' : 'LIVRE'} | ${noFuturo ? 'FUTURO' : 'PASSADO'}`);

    if (!conflitante && noFuturo) {
      const horaFim = somarUmaHora(horaStr);
      const fimStr = criarHorarioCompleto(dataISO, horaFim);

      horariosLivres.push({
        cliente_nome: cliente.nome_cliente || '',
        cliente_email: cliente.email_cliente || '',
        cliente_telefone: cliente.telefone_cliente || '',
        data: dataISO,
        dia_semana: formatarData(inicioSlot),
        horario: horaStr,
        horario_fim: horaFim,
        inicio: inicioStr,
        fim: fimStr,
        inicio_utc: inicioSlot.toISOString(),
        fim_utc: fimSlot.toISOString(),
        tipo: 'HORARIO_ALTERNATIVO'
      });

      console.log(`    ✅ Horário alternativo adicionado: ${horaStr} - ${horaFim}`);
    }

    if (horariosLivres.length >= MAX_HORARIOS) break;
  }
}

console.log(`\nRESULTADO FINAL:`);
console.log(`Total de horários encontrados: ${horariosLivres.length}`);

if (horariosLivres.length > 0) {
  horariosLivres.forEach((h, i) => {
    console.log(`${i + 1}. ${h.data} ${h.horario} - ${h.horario_fim} (${h.tipo})`);
  });
}

// Retorno
if (horariosLivres.length === 0) {
  return [{ json: { 
    mensagem: "❌ Não há horários disponíveis no período configurado.",
    horario_solicitado: horarioEspecificoSolicitado ? `${horarioEspecificoSolicitado.data} ${horarioEspecificoSolicitado.hora}` : null
  } }];
}

return horariosLivres.map(h => ({ json: h }));

const response = $json.output;

// Função para extrair valores com fallback
function extractValue(key, text) {
  const regex = new RegExp(`${key}:\\s*(.*)`);
  const match = text.match(regex);
  return match ? match[1].trim() : "";
}

// Extrair campos principais
const processo = extractValue("PROCESSO", response);
const resultado = extractValue("RESULTADO", response);
const acao = extractValue("AÇÃO", response);
const idEvento = extractValue("ID do evento", response);
const nomeCliente = extractValue("Nome do cliente", response);
const telefone = extractValue("Telefone", response);

// 🔥 Novo: extrair horário agendado (se existir)
const horarioAgendado = extractValue("Horário agendado", response);

// Verificar se algum campo está vazio
const faltandoCampos = [processo, resultado, acao, idEvento, nomeCliente, telefone]
  .some(v => v === "");

return [
  {
    json: {
      processo,
      resultado,
      acao,
      id_evento: idEvento,
      nome_cliente: nomeCliente,
      telefone,
      horario_agendado: horarioAgendado, // Novo campo
      faltando_campos: faltandoCampos
    },
  },
];

